import React, { useState, useEffect } from "react";
import {
  X,
  Calendar,
  Clock,
  Users,
  Mail,
  Eye,
  EyeOff,
  HelpCircle,
  CheckCircle,
  MapPin,
  Dice3,
  Phone,
} from "lucide-react";
import { useReservationFlow } from "../../hooks/useReservationFlow";
import { Button } from "../ui/Button";
import { Input } from "../ui/Input";
import { Card } from "../ui/Card";
import { Badge } from "../ui/Badge";
import ProgressIndicator from "./ProgressIndicator";
import { BookingSummary } from "./BookingSummary";
import type { Venue, Game } from "../../types/reservation.types";
import {
  isValidEmail,
  formatCardNumber,
  formatExpiryDate,
  isValidCardNumber,
  isValidExpiryDate,
  isValidCVV,
  formatCurrency,
} from "../../utils/validation";
import { handleConfirmReservation } from "../../utils/createReservation";

interface ReservationModalProps {
  isOpen: boolean;
  onClose: () => void;
  venue: Venue;
}

const TIME_SLOTS = [
  "5:30 PM",
  "6:00 PM",
  "6:30 PM",
  "7:00 PM",
  "7:30 PM",
  "8:00 PM",
  "8:30 PM",
];

const MOCK_GAMES: Game[] = [
  {
    id: "1",
    name: "Wingspan",
    image:
      "data:image/webp;base64,",
    complexity: "Medium",
    players: "1-5 players",
    duration: "40-70 min",
    price: 3,
    tags: ["Strategy", "Tableau"],
  },
  {
    id: "2",
    name: "Dune: Imperium - Uprising",
    image:
      "data:image/jpeg;base64,",
    complexity: "Medium",
    players: "1-6 players",
    duration: "60-120 min",
    price: 3,
    tags: ["Strategy", "Tableau"],
  },
  {
    id: "3",
    name: "Scythe Board Game",
    image:
      "data:image/jpeg;base64,",
    complexity: "Hard",
    players: "1-5 players",
    duration: "90-115 min",
    price: 3,
    tags: ["Strategy"],
  },
];

export const ReservationModal: React.FC<ReservationModalProps> = ({
  isOpen,
  onClose,
  venue,
}) => {
  const {
    currentStep,
    data,
    updateBooking,
    updateUser,
    updatePayment,
    selectGame,
    setAuthentication,
    nextStep,
    prevStep,
    canProceed,
    reset,
  } = useReservationFlow();

  // Local state for each step
  const [date, setDate] = useState("");
  const [time, setTime] = useState("");
  const [partySize, setPartySize] = useState(4);
  const [selectedGameId, setSelectedGameId] = useState<string>();
  const [complexityFilter, setComplexityFilter] = useState<string | null>(null);
  const [email, setEmail] = useState("");
  const [emailError, setEmailError] = useState("");
  const [nameOnCard, setNameOnCard] = useState("");
  const [cardNumber, setCardNumber] = useState("");
  const [expiryDate, setExpiryDate] = useState("");
  const [cvv, setCvv] = useState("");
  const [showCvvInfo, setShowCvvInfo] = useState(false);
  const [password, setPassword] = useState("");
  const [showPassword, setShowPassword] = useState(false);
  const [passwordError, setPasswordError] = useState("");
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    if (isOpen && venue) {
      updateBooking({ venue } as any);
    }
  }, [isOpen, venue]);

  useEffect(() => {
    if (date || time || partySize) {
      updateBooking({ date, time, partySize } as any);
    }
  }, [date, time, partySize]);

  useEffect(() => {
    if (email && isValidEmail(email)) {
      updateUser({ email, phone: "", name: "" });
      setEmailError("");
    } else if (email) {
      setEmailError("Please enter a valid email address");
    }
  }, [email]);

  useEffect(() => {
    if (
      nameOnCard &&
      isValidCardNumber(cardNumber) &&
      isValidExpiryDate(expiryDate) &&
      isValidCVV(cvv)
    ) {
      updatePayment({ nameOnCard, cardNumber, expiryDate, cvv });
    }
  }, [nameOnCard, cardNumber, expiryDate, cvv]);

  useEffect(() => {
    if (isOpen) {
      document.body.style.overflow = "hidden";
    } else {
      document.body.style.overflow = "unset";
    }
    return () => {
      document.body.style.overflow = "unset";
    };
  }, [isOpen]);

  const handleClose = () => {
    reset();
    onClose();
  };

  const handleGameSelect = (game: Game) => {
    if (selectedGameId === game.id) {
      setSelectedGameId(undefined);
      selectGame(undefined);
    } else {
      setSelectedGameId(game.id);
      selectGame(game);
    }
  };

  const handlePasswordSubmit = () => {
    if (password.length < 8) {
      setPasswordError("Password must be at least 8 characters");
      return;
    }
    setAuthentication(true, false);
    setPasswordError("");
  };

  if (!isOpen) return null;

  const filteredGames = complexityFilter
    ? MOCK_GAMES.filter((game) => game.complexity === complexityFilter)
    : MOCK_GAMES;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center">
      <div
        className="absolute inset-0 bg-black/50 backdrop-blur-sm"
        onClick={handleClose}
      />

      <div className="relative w-full max-w-2xl max-h-[90vh] bg-white rounded-2xl shadow-2xl overflow-hidden flex flex-col">
        {/* Header */}
        <div
          className="self-stretch px-7 py-6 text-white flex flex-col justify-center items-center gap-5 max-w-175 rounded-t-lg bg-cover bg-center"
          style={{ backgroundImage: `url(${venue.poster})` }}
        >
          <div className="self-stretch inline-flex justify-start items-center gap-5">
            <img className="size-20 rounded-[5px]" src={venue.logo} />
            <div className="flex-1 inline-flex flex-col justify-start items-start gap-1">
              <div className="self-stretch justify-start text-xl font-bold">
                {venue.name}
              </div>
              <div className="size- inline-flex justify-start items-center gap-2">
                <div className="justify-start flex flex-row items-center text-base font-regular">
                  <img className="size-4 mr-1" src="/icons/star.svg" />
                  {venue.rating} ({venue.reviewCount ?? 0})
                </div>
                <span className="w-1.5 h-1.5 bg-white rounded-full ml-5"></span>
                <div className="size-1.25 bg-White rounded-full" />
                <div className="justify-start text-base font-regular">
                  {venue.location}
                </div>
              </div>
            </div>
          </div>
        </div>

        <div className="bg-white px-6 py-4">
          <ProgressIndicator currentStep={currentStep} />
        </div>

        {/* Content */}
        <div className="flex-1 overflow-y-auto">
          {/* STEP 0: WHEN */}
          {currentStep === 0 && (
            <div className="p-6 space-y-6">
              <h2 className="text-2xl font-bold text-gray-900">
                When will you be joining us?
              </h2>

              <Input
                type="date"
                label="Date"
                value={date}
                onChange={(e) => setDate(e.target.value)}
                min={new Date().toISOString().split("T")[0]}
                leftIcon={<Calendar className="w-5 h-5" />}
              />

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-3">
                  Time
                </label>
                <div className="grid grid-cols-4 gap-2">
                  {TIME_SLOTS.map((slot) => (
                    <Button
                      key={slot}
                      variant={time === slot ? "primary" : "outline"}
                      size="sm"
                      onClick={() => setTime(slot)}
                    >
                      {slot}
                    </Button>
                  ))}
                </div>
              </div>

              <div className="space-y-2">
                <label className="block text-sm font-medium text-gray-700">
                  Party Size
                </label>
                <div className="flex items-center justify-center gap-4 bg-gray-50 rounded-lg p-4">
                  <div className="flex items-center gap-3">
                    {[...Array(partySize)].map((_, i) => (
                      <Users key={i} className="w-6 h-6 text-amber-700" />
                    ))}
                  </div>
                </div>
                <p className="text-center text-lg font-medium text-gray-900">
                  {partySize} {partySize === 1 ? "guest" : "guests"}
                </p>
              </div>
            </div>
          )}

          {/* STEP 1: GAMES */}
          {currentStep === 1 && (
            <div className="p-6 space-y-6">
              <div>
                <h2 className="text-2xl font-bold text-gray-900 mb-1">
                  Would you like to reserve a game?
                </h2>
                <p className="text-gray-600 flex items-center gap-2">
                  We'll have it ready for you
                  <Badge variant="warning" size="sm">
                    +$3/game
                  </Badge>
                </p>
              </div>

              <div>
                <p className="text-sm text-gray-600 mb-3">
                  Select one game per reservation
                </p>
                <div className="space-y-2">
                  <p className="text-xs font-medium text-gray-500 uppercase tracking-wide">
                    Complexity Level
                  </p>
                  <div className="flex gap-2">
                    {["Easy", "Medium", "Hard"].map((level) => (
                      <Button
                        key={level}
                        variant={
                          complexityFilter === level ? "secondary" : "outline"
                        }
                        size="sm"
                        onClick={() =>
                          setComplexityFilter(
                            complexityFilter === level ? null : level,
                          )
                        }
                      >
                        <div className="flex items-center gap-2">
                          <div className="flex gap-0.5">
                            {[...Array(3)].map((_, i) => (
                              <div
                                key={i}
                                className={`w-2 h-2 rounded-full ${
                                  i <
                                  { Easy: 1, Medium: 2, Hard: 3 }[
                                    level as keyof typeof complexityFilter
                                  ]
                                    ? complexityFilter === level
                                      ? "bg-white"
                                      : "bg-amber-900"
                                    : "bg-gray-300"
                                }`}
                              />
                            ))}
                          </div>
                          {level}
                        </div>
                      </Button>
                    ))}
                  </div>
                </div>
              </div>

              <div className="space-y-3">
                {filteredGames.map((game) => {
                  const isSelected = selectedGameId === game.id;
                  return (
                    <button
                      key={game.id}
                      onClick={() => handleGameSelect(game)}
                      className={`w-full flex items-start gap-4 p-4 rounded-lg border-2 transition-all ${
                        isSelected
                          ? "border-teal-500 bg-teal-50"
                          : "border-gray-200 bg-white hover:border-gray-300"
                      }`}
                    >
                      <img
                        src={game.image}
                        alt={game.name}
                        className="w-20 h-20 rounded-lg object-cover flex-shrink-0"
                      />

                      <div className="flex-1 text-left">
                        <div className="flex items-start justify-between mb-2">
                          <h3 className="font-semibold text-gray-900">
                            {game.name}
                          </h3>
                          <div className="flex gap-0.5 ml-2">
                            {[...Array(3)].map((_, i) => (
                              <div
                                key={i}
                                className={`w-2 h-2 rounded-full ${
                                  i <
                                  { Easy: 1, Medium: 2, Hard: 3 }[
                                    game.complexity
                                  ]
                                    ? "bg-amber-900"
                                    : "bg-gray-300"
                                }`}
                              />
                            ))}
                          </div>
                          <span className="ml-2 text-sm text-gray-600">
                            {game.complexity}
                          </span>
                        </div>

                        <div className="flex items-center gap-4 text-sm text-gray-600 mb-2">
                          <div className="flex items-center gap-1">
                            <Users className="w-4 h-4" />
                            {game.players}
                          </div>
                          <div className="flex items-center gap-1">
                            <Clock className="w-4 h-4" />
                            {game.duration}
                          </div>
                        </div>

                        <div className="flex gap-2">
                          {game.tags.map((tag) => (
                            <Badge key={tag} variant="error" size="sm">
                              {tag}
                            </Badge>
                          ))}
                        </div>
                      </div>
                    </button>
                  );
                })}
              </div>

              <Button variant="ghost" fullWidth>
                Skip - I'll browse when I'm there
              </Button>
            </div>
          )}

          {/* STEP 2: ACCOUNT */}
          {currentStep === 2 && (
            <div className="p-6 space-y-6">
              <div>
                <h2 className="text-2xl font-bold text-gray-900 mb-2">
                  Almost there!
                </h2>
                <p className="text-gray-600">
                  Where should we send the confirmation?
                </p>
              </div>

              <Input
                type="email"
                label="Email address"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                placeholder="you@example.com"
                error={emailError}
              />

              <div className="relative">
                <div className="absolute inset-0 flex items-center">
                  <div className="w-full border-t border-gray-300" />
                </div>
                <div className="relative flex justify-center text-sm">
                  <span className="px-4 bg-white text-gray-500">or</span>
                </div>
              </div>

              <Button variant="outline" fullWidth>
                <div className="flex items-center gap-3">
                  <svg className="w-5 h-5" viewBox="0 0 24 24">
                    <path
                      fill="#4285F4"
                      d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z"
                    />
                    <path
                      fill="#34A853"
                      d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z"
                    />
                    <path
                      fill="#FBBC05"
                      d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z"
                    />
                    <path
                      fill="#EA4335"
                      d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z"
                    />
                  </svg>
                  Continue with Google
                </div>
              </Button>

              <Button variant="ghost" fullWidth>
                Cancel
              </Button>
            </div>
          )}

          {/* STEP 3: PAYMENT */}
          {currentStep === 3 && (
            <div className="p-6 space-y-6">
              <div>
                <h2 className="text-2xl font-bold text-gray-900 mb-2">
                  Payment Method
                </h2>
                <p className="text-gray-600">
                  All transactions are secure and encrypted
                </p>
              </div>

              <Input
                type="text"
                label="Name on Card"
                value={nameOnCard}
                onChange={(e) => setNameOnCard(e.target.value)}
                placeholder="John Doe"
              />

              <Input
                type="text"
                label="Card Number"
                value={cardNumber}
                onChange={(e) =>
                  setCardNumber(formatCardNumber(e.target.value))
                }
                placeholder="1234 5678 9012 3456"
                error={
                  cardNumber && !isValidCardNumber(cardNumber)
                    ? "Please enter a valid card number"
                    : ""
                }
                rightIcon={
                  <div className="flex gap-1">
                    <svg className="w-8 h-5" viewBox="0 0 48 32" fill="none">
                      <rect width="48" height="32" rx="4" fill="#1A1F71" />
                      <text
                        x="24"
                        y="20"
                        fontSize="12"
                        fontWeight="bold"
                        fill="white"
                        textAnchor="middle"
                      >
                        VISA
                      </text>
                    </svg>
                  </div>
                }
              />

              <div className="grid grid-cols-2 gap-4">
                <Input
                  type="text"
                  label="MM/YY"
                  value={expiryDate}
                  onChange={(e) =>
                    setExpiryDate(formatExpiryDate(e.target.value))
                  }
                  placeholder="12/25"
                  error={
                    expiryDate && !isValidExpiryDate(expiryDate)
                      ? "Invalid date"
                      : ""
                  }
                />

                <div className="relative">
                  <Input
                    type="text"
                    label={
                      <span className="flex items-center gap-1">
                        CVV
                        <button
                          type="button"
                          onMouseEnter={() => setShowCvvInfo(true)}
                          onMouseLeave={() => setShowCvvInfo(false)}
                          className="text-gray-400 hover:text-gray-600"
                        >
                          <HelpCircle className="w-4 h-4" />
                        </button>
                      </span>
                    }
                    value={cvv}
                    onChange={(e) =>
                      /^\d{0,4}$/.test(e.target.value) && setCvv(e.target.value)
                    }
                    placeholder="123"
                    maxLength={4}
                    error={cvv && !isValidCVV(cvv) ? "Invalid CVV" : ""}
                  />
                  {showCvvInfo && (
                    <div className="absolute top-full right-0 mt-2 p-3 bg-gray-900 text-white text-xs rounded-lg shadow-lg z-10 w-48">
                      The 3-digit security code on the back of your card
                    </div>
                  )}
                </div>
              </div>

              <Button variant="ghost" fullWidth>
                Cancel
              </Button>
            </div>
          )}

          {/* STEP 4: AUTH */}
          {currentStep === 4 && (
            <div className="p-6 space-y-6">
              <div>
                <h2 className="text-2xl font-bold text-gray-900 mb-2">
                  Almost there!
                </h2>
                <p className="text-gray-600">
                  Enter your password or checkout as guest to continue
                </p>
              </div>

              <Input
                type={showPassword ? "text" : "password"}
                label="Password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                onKeyDown={(e) => e.key === "Enter" && handlePasswordSubmit()}
                placeholder="At least 8 characters"
                error={passwordError}
                rightIcon={
                  <button
                    onClick={() => setShowPassword(!showPassword)}
                    className="text-gray-400 hover:text-gray-600"
                  >
                    {showPassword ? (
                      <EyeOff className="w-5 h-5" />
                    ) : (
                      <Eye className="w-5 h-5" />
                    )}
                  </button>
                }
              />
              <div className="flex justify-end">
                <Button variant="ghost" size="sm">
                  Forgot Password?
                </Button>
              </div>

              <div className="relative">
                <div className="absolute inset-0 flex items-center">
                  <div className="w-full border-t border-gray-300" />
                </div>
                <div className="relative flex justify-center text-sm">
                  <span className="px-4 bg-white text-gray-500">or</span>
                </div>
              </div>

              <Button
                variant="outline"
                fullWidth
                onClick={() => setAuthentication(false, true)}
              >
                Checkout as Guest
              </Button>

              <Button variant="ghost" fullWidth>
                Cancel
              </Button>
            </div>
          )}

          {/* STEP 5: CONFIRM */}
          {currentStep === 5 && data.booking && data.user && (
            <div className="p-6 space-y-6">
              <div>
                <h2 className="text-2xl font-bold text-gray-900 mb-2 flex items-center gap-2">
                  Ready to roll? 🎲
                </h2>
                <p className="text-gray-600">Let's make it official</p>
              </div>

              <BookingSummary booking={data.booking} showPricing={true} />

              <Card variant="default" padding="md" className="space-y-3">
                <p className="text-xs font-medium text-gray-500 uppercase tracking-wide">
                  Confirmation will be sent to
                </p>
                <div className="space-y-2">
                  <p className="font-semibold text-gray-900">
                    {data.user.name || "Chloe"}
                  </p>
                  <div className="flex items-center gap-2 text-gray-600">
                    <Mail className="w-4 h-4" />
                    <span className="text-sm">{data.user.email}</span>
                  </div>
                  {data.user.phone && (
                    <div className="flex items-center gap-2 text-gray-600">
                      <Phone className="w-4 h-4" />
                      <span className="text-sm">{data.user.phone}</span>
                    </div>
                  )}
                </div>
              </Card>
            </div>
          )}

          {/* STEP 6: SUCCESS */}
          {currentStep === 6 && data.booking && data.user && (
            <div className="p-6 space-y-6">
              <div className="text-center space-y-4">
                <div className="inline-flex items-center justify-center w-16 h-16 rounded-full bg-teal-100">
                  <CheckCircle className="w-10 h-10 text-teal-500" />
                </div>
                <div>
                  <h2 className="text-2xl font-bold text-gray-900 mb-2">
                    You're all set!
                  </h2>
                  <p className="text-gray-600">
                    Confirmation sent to {data.user.email}
                  </p>
                </div>
              </div>

              <BookingSummary booking={data.booking} showPricing={true} />

              <div className="space-y-3">
                <p className="text-center text-gray-600">
                  Need to make changes?
                </p>
                <Button variant="ghost" fullWidth>
                  Modify or cancel reservation
                </Button>
              </div>
            </div>
          )}
        </div>

        {/* Footer */}
        <div className="border-t border-gray-200 bg-white">
          {currentStep !== 6 ? (
            <div className="p-6 space-y-4">
              <div className="grid grid-cols-2 gap-3">
                <Button
                  variant="outline"
                  disabled={currentStep === 0}
                  onClick={prevStep}
                >
                  Back
                </Button>
                <Button
                  variant="primary"
                  disabled={!canProceed || loading}
                  onClick={
                    currentStep === 5 ? () => handleConfirmReservation(data, nextStep, setLoading) : nextStep
                  }
                  className={loading ? "opacity-75" : ""}
                >
                  {loading ? "Creating..." : currentStep === 5 ? "Confirm" : "Continue"}
                </Button>
              </div>
              <div className="text-center text-xs text-gray-500">
                Powered by{" "}
                <span className="text-teal-600 font-semibold">GATORE</span>
              </div>
            </div>
          ) : (
            <div className="p-6">
              <div className="text-center text-xs text-gray-500">
                Powered by{" "}
                <span className="text-teal-600 font-semibold">GATORE</span>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};
